  "instructions": {
    "text_instructions": [
      {
        "id": "01f13a441cf416d9bbfb5e9fbfda1e60",
        "content": [
          "ALWAYS ftiler on experiments present in \r\n",
          "select exp_id\r\n",
          "from bi_output_product_analytics_abtoro_storage_experiments_md \r\n",
          "WHERE (NOT(`exp_type` IN ('Exclude from Meta-analysis')))\r\n",
          "\r\n",
          "This shoudl be the first step you do in your query and communicate only info related to exp_ids that is result of the above. "
        ]
      }
    ],
    "example_question_sqls": [
      {
        "id": "01f13a4685cd1a13b2fae6372fd9a69b",
        "question": [
          "Which experiments have early alerting violations in the last 3 days and what are their OEC metrics and violating variants?"
        ],
        "sql": [
          "SELECT\n",
          "  `exp_name` AS `Experiment`,\n",
          "  INITCAP(REPLACE(`early_alerting_metric`, '_', ' ')) AS `OEC Metric`,\n",
          "  `early_alerting_yeast_latest_check_violating_variants` AS `Violating Variants`\n",
          "FROM main.`product_analytics_stg`.`bi_output_product_analytics_abtoro_storage_experiments_md`\n",
          "WHERE\n",
          "  (`early_alerting_yeast_latest_check_max_value` >= `early_alerting_yeast_bound`) AND\n",
          "  (`early_alerting_yeast_latest_check_time` > (CURRENT_TIMESTAMP - interval 3 days))"
        ]
      }
    ]
